const embeddingResponse = $input.first().json;
const email = $('Entrada do Formulario').first().json.email;
const embedding = embeddingResponse.data[0].embedding;
const vectorStr = '[' + embedding.join(',') + ']';

// Monta query semantica
const semanticQuery = "SELECT chunk_id, content, metadata, 1 - (embedding <=> '" + vectorStr + "'::vector) AS score FROM documents ORDER BY embedding <=> '" + vectorStr + "'::vector LIMIT 20";

// Extrai termos para busca lexical
const stopwords = new Set([
  'para', 'com', 'por', 'que', 'uma', 'uns', 'das', 'dos', 'nos', 'nas',
  'seu', 'sua', 'orcamento', 'gostaria', 'receber', 'enviem', 'envie',
  'quero', 'favor', 'att', 'ola', 'seguintes', 'produto', 'produtos',
  'solicitacao', 'abaixo', 'segue', 'bom', 'dia', 'tarde', 'noite'
]);
const codes = email.match(/\b\d{6,7}\b/g) || [];
const words = (email.match(/\b[A-Za-z\u00C0-\u00FF0-9]{4,}\b/g) || [])
  .filter(w => !stopwords.has(w.toLowerCase()))
  .slice(0, 20);

const conditions = [];
codes.forEach(c => conditions.push("metadata->>'codigo_sap' = '" + c + "'"));
words.forEach(w => conditions.push("content ILIKE '%" + w + "%'"));
const whereClause = conditions.length > 0 ? conditions.join(' OR ') : '1=0';
const lexicalQuery = "SELECT chunk_id, content, metadata, 1.0 AS score FROM documents WHERE " + whereClause + " LIMIT 20";

return [{ json: { email, semanticQuery, lexicalQuery } }];

const items = $input.all();
const results = items.map((item, idx) => ({
  chunk_id: item.json.chunk_id,
  content: item.json.content,
  metadata: item.json.metadata,
  semantic_rank: idx + 1
}));
return [{ json: { semanticResults: results } }];

const items = $input.all();
const results = items.map((item, idx) => ({
  chunk_id: item.json.chunk_id,
  content: item.json.content,
  metadata: item.json.metadata,
  lexical_rank: idx + 1
}));
return [{ json: { lexicalResults: results } }];

const email = $('Entrada do Formulario').first().json.email;
const semanticResults = $input.first().json.semanticResults || [];
const lexicalResults = $input.first().json.lexicalResults || [];

const K = 60; // constante padrao do RRF
const scores = {};
const docs = {};

// Score semantico
semanticResults.forEach((doc, idx) => {
  const id = doc.chunk_id;
  if (!scores[id]) scores[id] = 0;
  scores[id] += 1 / (K + idx + 1);
  docs[id] = doc;
});

// Score lexical
lexicalResults.forEach((doc, idx) => {
  const id = doc.chunk_id;
  if (!scores[id]) scores[id] = 0;
  scores[id] += 1 / (K + idx + 1);
  if (!docs[id]) docs[id] = doc;
});

// Ordena por RRF score e pega top 10
const topDocs = Object.entries(scores)
  .sort((a, b) => b[1] - a[1])
  .slice(0, 10)
  .map(([id, score]) => ({ ...docs[id], rrf_score: score.toFixed(4) }));

const catalogText = topDocs.map(doc => {
  const m = doc.metadata;
  return 'Produto: ' + m.apresentacao +
    '\nCodigo SAP: ' + m.codigo_sap +
    '\nRRF Score: ' + doc.rrf_score +
    '\nPrecos PF  - ICMS12: R$' + m.icms_12_pf + ' | ICMS17: R$' + m.icms_17_pf + ' | ICMS18: R$' + m.icms_18_pf + ' | ICMS20: R$' + m.icms_20_pf +
    '\nPrecos PMC - ICMS12: R$' + m.icms_12_pmc + ' | ICMS17: R$' + m.icms_17_pmc + ' | ICMS18: R$' + m.icms_18_pmc + ' | ICMS20: R$' + m.icms_20_pmc +
    '\nDescricao: ' + doc.content;
}).join('\n\n---\n\n');

const formatoJSON = '{"itens":[{"produto":"","codigo":"","quantidade":0,"preco_unitario":0.0,"preco_total":0.0}],"cliente":{"tipo":"","uf":""},"total":0.0}';

const systemMessage = 'Voce e um sistema de cotacao de medicamentos farmaceuticos. '
  + 'Receberá uma mensagem de solicitacao de orcamento e produtos encontrados no catalogo ordenados por relevancia (RRF Score). '
  + 'Sua tarefa: '
  + '1) Identificar quais produtos correspondem ao solicitado. '
  + '2) Extrair quantidades (padrao 1 se nao informado). '
  + '3) Identificar tipo de cliente: PF, PJ ou Revenda. '
  + '4) Identificar UF se mencionada. '
  + '5) Calcular precos: PF e PJ usam icms_17_pf, Revenda usa icms_17_pmc, sem UF usa icms_17_pf. '
  + '6) preco_total = quantidade x preco_unitario. '
  + '7) Somar total geral. '
  + 'Responda APENAS com JSON valido, sem markdown, sem texto adicional: '
  + formatoJSON;

const userMessage = 'Mensagem do cliente:\n' + email
  + '\n\nProdutos mais relevantes (ordenados por RRF Score):\n\n' + catalogText;

const body = {
  model: 'gemma-3n-e4b-it-text',
  messages: [
    { role: 'system', content: systemMessage },
    { role: 'user', content: userMessage }
  ],
  temperature: 0.1,
  max_tokens: 1024,
  stream: false
};

return [{ json: { body } }];

const response = $input.first().json;
const content = response.choices[0].message.content.trim();
try {
  const jsonStr = content.replace(/```json/g, '').replace(/```/g, '').trim();
  const orcamento = JSON.parse(jsonStr);
  return [{ json: orcamento }];
} catch(e) {
  return [{ json: { erro: 'Falha ao parsear JSON', raw: content } }];
}

const orc = $input.first().json;
const esc = s => String(s == null ? '' : s)
  .replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;');
const brl = v => 'R$ ' + Number(v || 0).toFixed(2).replace('.', ',')
  .replace(/\B(?=(\d{3})+(?!\d))/g, '.');

let body;
if (orc && orc.erro) {
  body = '<div class="erro"><h2>Não foi possível gerar o orçamento</h2>'
    + '<p>' + esc(orc.erro) + '</p><pre>' + esc(orc.raw || '') + '</pre></div>';
} else {
  const itens = (orc.itens || []);
  const cli = orc.cliente || {};
  const linhas = itens.map(it =>
    '<tr><td>' + esc(it.produto) + '</td>'
    + '<td class="c">' + esc(it.codigo) + '</td>'
    + '<td class="r">' + esc(it.quantidade) + '</td>'
    + '<td class="r">' + brl(it.preco_unitario) + '</td>'
    + '<td class="r">' + brl(it.preco_total) + '</td></tr>'
  ).join('');
  const tipo = esc(cli.tipo || '—');
  const uf = esc(cli.uf || '—');
  body =
    '<div class="meta">'
    + '<div><span class="lbl">Tipo de cliente</span><span class="val">' + tipo + '</span></div>'
    + '<div><span class="lbl">UF</span><span class="val">' + uf + '</span></div>'
    + '<div><span class="lbl">Itens</span><span class="val">' + itens.length + '</span></div>'
    + '</div>'
    + '<table><thead><tr><th>Produto</th><th>Código SAP</th>'
    + '<th class="r">Qtd.</th><th class="r">Preço unit.</th><th class="r">Subtotal</th>'
    + '</tr></thead><tbody>' + linhas + '</tbody>'
    + '<tfoot><tr><td colspan="4" class="r">Total</td>'
    + '<td class="r total">' + brl(orc.total) + '</td></tr></tfoot></table>';
}

const html =
'<!DOCTYPE html><html lang="pt-BR"><head><meta charset="UTF-8">'
+ '<meta name="viewport" content="width=device-width, initial-scale=1">'
+ '<title>Orçamento Farmacêutico</title><style>'
+ ':root{--ac:#2f6df6;--ink:#1f2733;--mut:#67727f;--line:#e4e8ef;--bg:#f5f7fb}'
+ '*{box-sizing:border-box}body{margin:0;background:var(--bg);color:var(--ink);'
+ 'font-family:-apple-system,Segoe UI,Roboto,Helvetica,Arial,sans-serif;line-height:1.5}'
+ '.sheet{max-width:820px;margin:32px auto;background:#fff;border:1px solid var(--line);'
+ 'border-radius:14px;overflow:hidden;box-shadow:0 6px 24px rgba(20,40,80,.06)}'
+ '.hd{background:linear-gradient(135deg,#2f6df6,#5b8bff);color:#fff;padding:26px 30px}'
+ '.hd h1{margin:0;font-size:22px;letter-spacing:-.3px}'
+ '.hd p{margin:4px 0 0;opacity:.9;font-size:13.5px}'
+ '.body{padding:24px 30px 30px}'
+ '.meta{display:flex;gap:14px;flex-wrap:wrap;margin-bottom:18px}'
+ '.meta>div{flex:1;min-width:120px;background:var(--bg);border:1px solid var(--line);'
+ 'border-radius:10px;padding:10px 14px}'
+ '.lbl{display:block;font-size:11px;text-transform:uppercase;letter-spacing:.5px;color:var(--mut)}'
+ '.val{display:block;font-size:17px;font-weight:600;margin-top:2px}'
+ 'table{width:100%;border-collapse:collapse;font-size:14px}'
+ 'th,td{padding:10px 12px;border-bottom:1px solid var(--line);text-align:left}'
+ 'th{font-size:11.5px;text-transform:uppercase;letter-spacing:.4px;color:var(--mut);'
+ 'background:#fafbfe}.r{text-align:right}.c{text-align:center;color:var(--mut)}'
+ 'tfoot td{border-top:2px solid var(--ink);border-bottom:none;font-weight:700;font-size:15px}'
+ '.total{color:var(--ac);font-size:18px}'
+ '.erro{padding:10px}.erro pre{background:#fff5f5;border:1px solid #ffd6d6;'
+ 'border-radius:8px;padding:12px;overflow:auto;font-size:12px}'
+ '.ft{padding:14px 30px;border-top:1px solid var(--line);color:var(--mut);font-size:12px;text-align:center}'
+ '</style></head><body><div class="sheet">'
+ '<div class="hd"><h1>Orçamento Farmacêutico</h1>'
+ '<p>Gerado automaticamente por busca híbrida (semântica + lexical) + LLM</p></div>'
+ '<div class="body">' + body + '</div>'
+ '<div class="ft">Valores sujeitos a confirmação. Documento gerado por sistema RAG.</div>'
+ '</div></body></html>';

return [{ json: { html } }];
